(12, 3, '7-Week Budget Adventure: Tokyo & Dubai from Vizag', 'Plan a 7 week budget trip for 4 friends starting from Visakhapatnam (Vizag), going first to Tokyo and then Dubai. Keep it low-cost, include cheap flights, budget stays, local transport, a week-by-week schedule, and save this trip in trip drafts with an average per-person split.', 'openai', 'Embark on a 49‑day journey from Visakhapatnam to Tokyo and Dubai, designed for four friends on a budget of ₹294,000–₹401,800. The plan balances low‑cost flights, budget stays, local transport, and cultural experiences while keeping daily spending realistic. Each week’s itinerary highlights key sights, food spots, and activities, with an estimated weekly budget and travel tips. The trip is saved in drafts and split evenly among the travelers.', 'Visakhapatnam', 'Tokyo, Dubai', 49, 4, 'friends', 294000.0, 401800.0, 'budget stay', 'flight + local cab', '["sightseeing", "culture", "food"]'::json, 'Week-by-week schedule included, trip saved in drafts, average per-person split', '{"title": "7-Week Budget Adventure: Tokyo & Dubai from Vizag", "summary": "Embark on a 49\u2011day journey from Visakhapatnam to Tokyo and Dubai, designed for four friends on a budget of \u20b9294,000\u2013\u20b9401,800. The plan balances low\u2011cost flights, budget stays, local transport, and cultural experiences while keeping daily spending realistic. Each week\u2019s itinerary highlights key sights, food spots, and activities, with an estimated weekly budget and travel tips. The trip is saved in drafts and split evenly among the travelers.", "source": "openai", "prompt": "Plan a 7 week budget trip for 4 friends starting from Visakhapatnam (Vizag), going first to Tokyo and then Dubai. Keep it low-cost, include cheap flights, budget stays, local transport, a week-by-week schedule, and save this trip in trip drafts with an average per-person split.", "plan_form": {"origin": "Visakhapatnam", "destination": "Tokyo, Dubai", "days": 49, "travelers": 4, "group_type": "friends", "budget_min": 294000.0, "budget_max": 401800.0, "stay_type": "budget stay", "travel_mode": "flight + local cab", "interests": ["sightseeing", "culture", "food"], "notes": "Week-by-week schedule included, trip saved in drafts, average per-person split"}, "budget_categories": [{"category": "Transport", "min_amount": 105840.0, "max_amount": 144648.0, "per_person_min": 26460.0, "per_person_max": 36162.0, "tip": "Lock fares early and keep airport cab/transfer costs in this bucket."}, {"category": "Stay", "min_amount": 64680.0, "max_amount": 88396.0, "per_person_min": 16170.0, "per_person_max": 22099.0, "tip": "Estimate 49 nights with taxes; budget stay stays can swing heavily on weekends."}, {"category": "Food", "min_amount": 67620.0, "max_amount": 92414.0, "per_person_min": 16905.0, "per_person_max": 23103.5, "tip": "Mix daily meals, cafe stops, water, snacks, and one group dinner buffer."}, {"category": "Activities", "min_amount": 23520.0, "max_amount": 32144.0, "per_person_min": 5880.0, "per_person_max": 8036.0, "tip": "Reserve room for tickets, adventure activities, guide fees, or entry permits."}, {"category": "Local buffer", "min_amount": 32340.0, "max_amount": 44198.0, "per_person_min": 8085.0, "per_person_max": 11049.5, "tip": "Use this for emergency cash, medicine, SIM/data, tips, and small unplanned purchases."}], "planning_notes": ["Starting point considered: Visakhapatnam", "Estimated daily budget per person: \u20b91500.0 - \u20b92050.0", "Keep a 5-10% emergency buffer for surge pricing, weather changes, or last-minute route changes.", "If this turns into an actual trip expense, paste the final story above and FairSplit AI will settle the real payments.", "Group style set as: friends", "Interest focus: sightseeing, culture, food", "Planning preference noted: Week-by-week schedule included, trip saved in drafts, average per-person split"], "hotels": [{"hotel_name": "Sakura Guest House", "area": "Shinjuku", "hotel_address": "2-1-1 Shi