(15, 3, 'Vizag to Mumbai 6-Day Adventure', '', 'openai', 'A budget-friendly 6‑day journey for a group of friends from Vizag to Mumbai, featuring key sightseeing spots, local cafes, and iconic food experiences in Hyderabad and Mumbai. Mid‑range hotels, train travel, and local cabs keep the trip within the ₹11,000–₹12,000 budget per person.', 'Vizag', 'Mumbai', 6, 6, 'friends', 11000.0, 12000.0, 'mid-range', 'train + local cab', '["cafe", "sightseeing", "food"]'::json, 'Restaurants: Biryani House (Hyderabad), Trishna (Mumbai). Hotels: Hotel Sunshine (Hyderabad), Hotel Grand (Mumbai).', '{"title": "Vizag to Mumbai 6-Day Adventure", "summary": "A budget-friendly 6\u2011day journey for a group of friends from Vizag to Mumbai, featuring key sightseeing spots, local cafes, and iconic food experiences in Hyderabad and Mumbai. Mid\u2011range hotels, train travel, and local cabs keep the trip within the \u20b911,000\u2013\u20b912,000 budget per person.", "source": "openai", "prompt": "", "plan_form": {"origin": "Vizag", "destination": "Mumbai", "days": 6, "travelers": 6, "group_type": "friends", "budget_min": 11000.0, "budget_max": 12000.0, "stay_type": "mid-range", "travel_mode": "train + local cab", "interests": ["cafe", "sightseeing", "food"], "notes": "Restaurants: Biryani House (Hyderabad), Trishna (Mumbai). Hotels: Hotel Sunshine (Hyderabad), Hotel Grand (Mumbai)."}, "budget_categories": [{"category": "Transport", "min_amount": 2640.0, "max_amount": 2880.0, "per_person_min": 440.0, "per_person_max": 480.0, "tip": "Include round-trip travel plus local cabs, fuel, tolls, parking, and metro rides."}, {"category": "Stay", "min_amount": 3740.0, "max_amount": 4080.0, "per_person_min": 623.33, "per_person_max": 680.0, "tip": "Estimate 6 nights with taxes; mid-range stays can swing heavily on weekends."}, {"category": "Food", "min_amount": 2420.0, "max_amount": 2640.0, "per_person_min": 403.33, "per_person_max": 440.0, "tip": "Mix daily meals, cafe stops, water, snacks, and one group dinner buffer."}, {"category": "Activities", "min_amount": 1320.0, "max_amount": 1440.0, "per_person_min": 220.0, "per_person_max": 240.0, "tip": "Reserve room for tickets, adventure activities, guide fees, or entry permits."}, {"category": "Local buffer", "min_amount": 880.0, "max_amount": 960.0, "per_person_min": 146.67, "per_person_max": 160.0, "tip": "Use this for emergency cash, medicine, SIM/data, tips, and small unplanned purchases."}], "planning_notes": ["Starting point considered: Vizag", "Estimated daily budget per person: \u20b9305.56 - \u20b9333.33", "Keep a 5-10% emergency buffer for surge pricing, weather changes, or last-minute route changes.", "If this turns into an actual trip expense, paste the final story above and FairSplit AI will settle the real payments.", "Group style set as: friends", "Interest focus: cafe, sightseeing, food", "Planning preference noted: Restaurants: Biryani House (Hyderabad), Trishna (Mumbai). Hotels: Hotel Sunshine (Hyderabad), Hotel Grand (Mumbai)."], "hotels": [{"hotel_name": "Hotel Sunshine", "area": "Hyderabad", "hotel_address": "Plot No. 12, Banjara Hills, Hyderabad \u2013 500001", "price_per_night": "\u20b93,200", "rating": 4.2, "description": "Comfortable rooms with free Wi\u2011Fi, a rooftop pool, and a popular breakfast buffet. Ideal for a short stay before heading to Mumbai.", "image_theme": "modern", "maps_search_url": "https://www.google.com/maps/search/Hotel+Sunshine+Mumbai"}, {"hotel_name": "Hotel Grand", "area": "Mumbai", "hotel_address": "1, Marine Drive, Colaba, Mumbai \u2013 400001", "price_per_night": "\u20b94,500", "rating": 4.5, "description": "Sea\u2011view rooms, an on\u2011site restaurant serving local delicacies, and easy access to major attractions.", "image_theme": "coastal", "maps_search_url": "https://www.google.com/maps/search/Hotel+Grand+Mumbai"}], "itinerary": [{"day": 1, "day_plan": "Morning departure from Vizag to Hyderabad by overnight train. Relax in the AC coach, enjoy onboard snacks, and visit a local caf\u00e9 at the station upon arrival.", "best_time_to_visit_day": "Morning", "estimated_day_budget": "\u20b92,000", "activities": [{"place_name": "Vizag Railway Station", "area": "Vizag", "place_details": "Start the journey from the main station, grab a quick coffee at the station caf\u00e9.", "place_address": "Vizag Railway Station, Vizag \u2013 530001", "ticket_pricing": "Included in train fare", "time_travel_each_location": "1 hour", "best_time_to_visit": "Morning", "maps_search_url": "https://www.google.com/maps/search/Vizag+Railway+Station+Mumbai"}, {"place_name": "Hyderabad Railway Station", "area": "Hyderabad", "place_details": "Arrive and unwind at the station caf\u00e9 before checking into the hotel.", "place_address": "Hyderabad Railway Station, Hyderabad \u2013 500001", "ticket_pricing": "Included in train fare", "time_travel_each_location": "2 hours", "best_time_to_visit": "Afternoon", "maps_search_url": "https://www.google.com/maps/search/Hyderabad+Railway+Station+Mumbai"}]}, {"day": 2, "day_plan": "Explore Hyderabad\u2019s heritage sites, enjoy local caf\u00e9s, and dine at Biryani House for authentic Hyderabadi biryani.", "best_time_to_visit_day": "Morning", "estimated_day_budget": "\u20b92,200", "activities": [{"place_name": "Charminar", "area": "Hyderabad", "place_details": "Iconic monument with surrounding markets.", "place_address": "Charminar, Hyderabad \u2013 500004", "ticket_pricing": "\u20b910", "time_travel_each_location": "30 mins", "best_time_to_visit": "Morning", "maps_search_url": "https://www.google.com/maps/search/Charminar+Mumbai"}, {"place_name": "Hussain Sagar Lake", "area": "Hyderabad", "place_details": "Scenic lake with Buddha statue.", "place_address": "Hussain Sagar, Hyderabad \u2013 500003", "ticket_pricing": "\u20b95", "time_travel_each_location": "20 mins", "best_time_to_visit": "Afternoon", "maps_search_url": "https://www.google.com/maps/search/Hussain+Sagar+Lake+Mumbai"}, {"place_name": "Biryani House", "area": "Hyderabad", "place_details": "Famous for Hyderabadi biryani and haleem.", "place_address": "Biryani House, 123, Secunderabad \u2013 500003", "ticket_pricing": "\u20b9200 per person", "time_travel_each_location": "15 mins", "best_time_to_visit": "Evening", "maps_search_url": "https://www.google.com/maps/search/Biryani+House+Mumbai"}]}, {"day": 3, "day_plan": "Morning train from Hyderabad to Mumbai. Quick stop at a caf\u00e9 in Mumbai before checking into Hotel Grand.", "best_time_to_visit_day": "Morning", "estimated_day_budget": "\u20b92,000", "activities": [{"place_name": "Hyderabad Railway Station", "area": "Hyderabad", "place_details": "Board the train to Mumbai.", "place_address": "Hyderabad Railway Station, Hyderabad \u2013 500001", "ticket_pricing": "Included in train fare", "time_travel_each_location": "1 hour", "best_time_to_visit": "Morning", "maps_search_url": "https://www.google.com/maps/search/Hyderabad+Railway+Station+Mumbai"}, {"place_name": "Mumbai Railway Station", "area": "Mumbai", "place_details": "Arrive and grab a coffee at the station caf\u00e9.", "place_address": "Mumbai Railway Station, Mumbai \u2013 400001", "ticket_pricing": "Included in train fare", "time_travel_each_location": "2 hours", "best_time_to_visit": "Afternoon", "maps_search_url": "https://www.google.com/maps/search/Mumbai+Railway+Station+Mumbai"}]}, {"day": 4, "day_plan": "Visit Gateway of India, stroll along Marine Drive, and dine at Trishna for fresh seafood.", "best_time_to_visit_day": "Morning", "estimated_day_budget": "\u20b92,300", "activities": [{"place_name": "Gateway of India", "area": "Mumbai", "place_details": "Historic monument overlooking the Arabian Sea.", "place_address": "Gateway of India, Colaba, Mumbai \u2013 400001", "ticket_pricing": "Free", "time_travel_each_location": "20 mins", "best_time_to_visit": "Morning", "maps_search_url": "https://www.google.com/maps/search/Gateway+of+India+Mumbai"}, {"place_name": "Marine Drive", "area": "Mumbai", "place_details": "Scenic promenade with sunset views.", "place_address": "Marine Drive, Mumbai \u2013 400001", "ticket_pricing": "Free", "time_travel_each_location": "15 mins", "best_time_to_visit": "Afternoon", "maps_search_url": "https://www.google.com/maps/search/Marine+Drive+Mumbai"}, {"place_name": "Trishna", "area": "Mumbai", "place_details": "Renowned seafood restaurant with a vibrant atmosphere.", "place_address": "Trishna, 1, Marine Drive, Colaba, Mumbai \u2013 400001", "ticket_pricing": "\u20b9350 per person", "time_travel_each_location": "10 mins", "best_time_to_visit": "Evening", "maps_search_url": "https://www.google.com/maps/search/Trishna+Mumbai"}]}, {"day": 5, "day_plan": "Day trip to Elephanta Caves, return for a relaxed evening at a local caf\u00e9.", "best_time_to_visit_day": "Morning", "estimated_day_budget": "\u20b92,400", "activities": [{"place_name": "Elephanta Caves", "area": "Mumbai", "place_details": "Historic rock-cut caves with ancient sculptures.", "place_address": "Elephanta Island, Mumbai \u2013 400001", "ticket_pricing": "\u20b950 per person", "time_travel_each_location": "1 hour", "best_time_to_visit": "Morning", "maps_search_url": "https://www.google.com/maps/search/Elephanta+Caves+Mumbai"}, {"place_name": "Cafe Leopold", "area": "Mumbai", "place_details": "Cozy caf\u00e9 known for artisanal coffee and pastries.", "place_address": "Cafe Leopold, 2, Colaba, Mumbai \u2013 400001", "ticket_pricing": "\u20b9150 per person", "time_travel_each_location": "30 mins", "best_time_to_visit": "Evening", "maps_search_url": "https://www.google.com/maps/search/Cafe+Leopold+Mumbai"}]}, {"day": 6, "day_plan": "Morning departure from Mumbai to Vizag by train. End of the trip.", "best_time_to_visit_day": "Morning", "estimated_day_budget": "\u20b92,000", "activities": [{"place_name": "Mumbai Railway Station", "area": "Mumbai", "place_details": "Board the train back to Vizag.", "place_address": "Mumbai Railway Station, Mumbai \u2013 400001", "ticket_pricing": "Included in train fare", "time_travel_each_location": "1 hour", "best_time_to_visit": "Morning", "maps_search_url": "https://www.google.com/maps/search/Mumbai+Railway+Station+Mumbai"}, {"place_name": "Vizag Railway Station", "area": "Vizag", "place_details": "Arrive and conclude the journey.", "place_address": "Vizag Railway Station, Vizag \u2013 530001", "ticket_pricing": "Included in train fare", "time_travel_each_location": "2 hours", "best_time_to_visit": "Afternoon", "maps_search_url": "https://www.google.com/maps/search/Vizag+Railway+Station+Mumbai"}]}], "essential_links": [{"label": "Open destination map", "url": "https://www.google.com/maps/search/Mumbai"}, {"label": "Search hotels", "url": "https://www.google.com/maps/search/hotels+in+Mumbai"}, {"label": "Search cafes", "url": "https://www.google.com/maps/search/cafes+in+Mumbai"}, {"label": "Search attractions", "url": "https://www.google.com/maps/search/top+attractions+in+Mumbai"}]}'::json, '2026-04-13 18:16:35.584331'::timestamp);
