BEGIN;

-- Reset Neon so the local sample data can be imported cleanly.
TRUNCATE TABLE reviews, trip_plans, expenses, developer_profiles, users RESTART IDENTITY CASCADE;






SELECT setval(pg_get_serial_sequence('users', 'id'), COALESCE((SELECT MAX(id) FROM users), 1), true);

SELECT setval(pg_get_serial_sequence('expenses', 'id'), COALESCE((SELECT MAX(id) FROM expenses), 1), true);

SELECT setval(pg_get_serial_sequence('trip_plans', 'id'), COALESCE((SELECT MAX(id) FROM trip_plans), 1), true);

SELECT setval(pg_get_serial_sequence('reviews', 'id'), COALESCE((SELECT MAX(id) FROM reviews), 1), true);

COMMIT;